class Solution(object):
    def unhappyFriends(self, n, preferences, pairs):
        rank = [[0] * n for _ in range(n)]
        for i in range(n):
            for j, pref in enumerate(preferences[i]):
                rank[i][pref] = j
        pair_map = {}
        for x, y in pairs:
            pair_map[x] = y
            pair_map[y] = x
        unhappy = 0
        for x in range(n):
            y = pair_map[x]
            for u in preferences[x]:
                if u == y:
                    break
                v = pair_map[u]
                if rank[u][x] < rank[u][v]:
                    unhappy += 1
                    break
        return unhappy
